import SwiftUI
import KeyboardShortcuts

// MARK: - Preferences View

struct PreferencesView: View {
    @EnvironmentObject var appState: AppState
    @EnvironmentObject var modelManager: WhisperModelManager
    @EnvironmentObject var bleDeviceManager: BLEDeviceManager

    var body: some View {
        Form {
            // 语音引擎 Section
            Section("语音引擎") {
                Picker("转录引擎", selection: $appState.speechPipelineMode) {
                    ForEach(SpeechPipelineMode.allCases) { mode in
                        Text(mode.displayName).tag(mode)
                    }
                }
                Text("切换引擎后请重启 App 生效。Experimental 模式首次使用需下载模型（约 150MB）。")
                    .font(.caption)
                    .foregroundColor(.secondary)
            }

            // 录音源 Section
            Section("录音源") {
                Picker("当前录音源", selection: $appState.recordingSource) {
                    ForEach(RecordingSource.allCases) { source in
                        Text(source.displayName).tag(source)
                    }
                }
            }

            // 蓝牙设备管理 Section
            Section("蓝牙录音笔") {
                // 蓝牙状态
                HStack {
                    Image(systemName: bleDeviceManager.bluetoothPoweredOn
                          ? "checkmark.circle.fill" : "xmark.circle.fill")
                        .foregroundColor(bleDeviceManager.bluetoothPoweredOn ? .green : .red)
                    Text(bleDeviceManager.bluetoothPoweredOn ? "蓝牙已开启" : "蓝牙未开启")
                        .font(.caption)
                        .foregroundColor(.secondary)
                }

                // 连接状态
                HStack {
                    Circle()
                        .fill(bleConnectionStatusColor)
                        .frame(width: 8, height: 8)
                    Text(bleConnectionStatusText)
                        .foregroundColor(.secondary)
                    Spacer()

                    if bleDeviceManager.connectionState == .connected {
                        Button("断开") {
                            bleDeviceManager.disconnect()
                        }
                        .buttonStyle(.bordered)
                        .controlSize(.small)
                    }
                }

                // 电量显示
                if let battery = bleDeviceManager.batteryLevel {
                    HStack {
                        Text("电量")
                        Spacer()
                        if battery == 110 {
                            Text("充电中")
                                .foregroundColor(.green)
                        } else {
                            Text("\(battery)%")
                                .foregroundColor(battery <= 20 ? .red : .primary)
                        }
                    }
                }

                // 扫描和设备列表
                if bleDeviceManager.connectionState != .connected {
                    scanSection
                }
            }

            // Hotkey Section
            Section("快捷键") {
                HStack {
                    Text("录音快捷键")
                    Spacer()
                    KeyboardShortcuts.Recorder("", name: .toggleRecording)
                        .help("点击后按下新快捷键")
                }

                HStack {
                    Image(systemName: appState.accessibilityPermissionGranted
                          ? "checkmark.circle.fill" : "xmark.circle.fill")
                        .foregroundColor(appState.accessibilityPermissionGranted ? .green : .red)

                    Text(appState.accessibilityPermissionGranted
                         ? "辅助功能权限已授权"
                         : "辅助功能权限未授权（全局快捷键不可用）")
                        .font(.caption)
                        .foregroundColor(.secondary)

                    Spacer()

                    if !appState.accessibilityPermissionGranted {
                        Button("前往系统设置") {
                            openAccessibilitySettings()
                        }
                        .buttonStyle(.link)
                        .font(.caption)
                    }
                }
            }

            // Model Section
            Section("Whisper 模型") {
                ForEach(WhisperModel.allCases) { model in
                    ModelRow(
                        model: model,
                        isSelected: appState.selectedModel == model,
                        isSwitching: isSwitching,
                        modelManager: modelManager
                    ) {
                        guard !isSwitching else { return }
                        appState.selectedModel = model
                    }
                }

                Text("模型存储位置：~/Library/Application Support/VoicePepper/models/")
                    .font(.caption2)
                    .foregroundColor(.secondary)
            }

            // VAD Section
            Section("转录敏感度") {
                HStack {
                    Text("静音检测阈值")
                    Spacer()
                    Stepper("\(appState.vadSilenceThresholdMs) ms",
                            value: $appState.vadSilenceThresholdMs,
                            in: 200...2000,
                            step: 100)
                }
                Text("值越小，分段越频繁；值越大，段落越长")
                    .font(.caption)
                    .foregroundColor(.secondary)
            }
        }
        .formStyle(.grouped)
        .padding()
        .frame(width: 520, height: 640)
    }

    // MARK: BLE Scan Section

    private var scanSection: some View {
        VStack(alignment: .leading, spacing: 8) {
            HStack {
                Button(bleDeviceManager.connectionState == .scanning ? "扫描中…" : "扫描设备") {
                    bleDeviceManager.startScan()
                }
                .disabled(bleDeviceManager.connectionState == .scanning || !bleDeviceManager.bluetoothPoweredOn)
                .buttonStyle(.bordered)
                .controlSize(.small)

                if bleDeviceManager.connectionState == .scanning {
                    ProgressView()
                        .scaleEffect(0.6)
                }
            }

            if bleDeviceManager.discoveredDevices.isEmpty && bleDeviceManager.connectionState != .scanning {
                Text("未发现设备，请确保录音笔（A06）已开机并在附近")
                    .font(.caption)
                    .foregroundColor(.secondary)
            }

            ForEach(bleDeviceManager.discoveredDevices) { device in
                HStack {
                    VStack(alignment: .leading) {
                        Text(device.name)
                            .font(.body)
                        Text("信号: \(device.rssi) dBm")
                            .font(.caption)
                            .foregroundColor(.secondary)
                    }
                    Spacer()
                    Button("连接") {
                        bleDeviceManager.connect(deviceID: device.id)
                    }
                    .buttonStyle(.borderedProminent)
                    .controlSize(.small)
                }
            }
        }
    }

    // MARK: BLE Status Helpers

    private var bleConnectionStatusColor: Color {
        switch bleDeviceManager.connectionState {
        case .connected: return .green
        case .connecting, .reconnecting: return .orange
        default: return .red
        }
    }

    private var bleConnectionStatusText: String {
        switch bleDeviceManager.connectionState {
        case .connected: return "已连接"
        case .connecting: return "连接中…"
        case .reconnecting(let n): return "重连中 (\(n)/\(BLEReconnectPolicy.maxAttempts))"
        case .scanning: return "扫描中…"
        case .disconnected: return "未连接"
        }
    }

    /// 任意模型正在下载或加载时为 true，此时禁止切换
    private var isSwitching: Bool {
        modelManager.modelStates.values.contains {
            if case .downloading = $0 { return true }
            if case .loading = $0 { return true }
            return false
        }
    }

    private func openAccessibilitySettings() {
        let url = URL(string: "x-apple.systempreferences:com.apple.preference.security?Privacy_Accessibility")!
        NSWorkspace.shared.open(url)
    }
}

// MARK: - Model Row

private struct ModelRow: View {
    let model: WhisperModel
    let isSelected: Bool
    let isSwitching: Bool
    let modelManager: WhisperModelManager
    let onSelect: () -> Void

    var body: some View {
        Button(action: onSelect) {
            HStack(spacing: 10) {
                // 选中指示
                Image(systemName: isSelected ? "largecircle.fill.circle" : "circle")
                    .foregroundColor(isSelected ? .accentColor : .secondary)
                    .frame(width: 16)

                // 模型名称 + 推荐标签
                VStack(alignment: .leading, spacing: 2) {
                    HStack(spacing: 6) {
                        Text(model.displayName)
                            .fontWeight(isSelected ? .semibold : .regular)

                        if model.isRecommended {
                            Text("推荐")
                                .font(.caption2)
                                .fontWeight(.medium)
                                .padding(.horizontal, 5)
                                .padding(.vertical, 2)
                                .background(Color.yellow.opacity(0.25))
                                .foregroundColor(.orange)
                                .cornerRadius(4)
                        }
                    }

                    statusSubtitle
                }

                Spacer()

                statusTrailing
            }
            .contentShape(Rectangle())
        }
        .buttonStyle(.plain)
        .disabled(isSwitching && !isSelected)
        .opacity(isSwitching && !isSelected ? 0.45 : 1.0)
    }

    @ViewBuilder
    private var statusSubtitle: some View {
        switch resolvedState {
        case .downloading(let progress):
            VStack(alignment: .leading, spacing: 3) {
                ProgressView(value: progress)
                    .frame(width: 160)
                Text(String(format: "下载中 %.0f%%", progress * 100))
                    .font(.caption)
                    .foregroundColor(.secondary)
            }
        case .loading:
            Text("加载中…")
                .font(.caption)
                .foregroundColor(.secondary)
        case .failed:
            Text("下载失败，请检查网络连接")
                .font(.caption)
                .foregroundColor(.red)
        case .ready:
            if modelManager.activeModel == model {
                Text("使用中")
                    .font(.caption)
                    .foregroundColor(.green)
            } else {
                Text("已下载")
                    .font(.caption)
                    .foregroundColor(.secondary)
            }
        default:
            // idle / nil — check local file
            if modelManager.isModelDownloaded(model) {
                Text("已下载")
                    .font(.caption)
                    .foregroundColor(.secondary)
            } else {
                Text("未下载")
                    .font(.caption)
                    .foregroundColor(.secondary)
            }
        }
    }

    @ViewBuilder
    private var statusTrailing: some View {
        switch resolvedState {
        case .downloading:
            ProgressView()
                .scaleEffect(0.7)
        case .loading:
            ProgressView()
                .scaleEffect(0.7)
        case .failed:
            Image(systemName: "exclamationmark.circle.fill")
                .foregroundColor(.red)
        case .ready:
            if modelManager.activeModel == model {
                Image(systemName: "checkmark.circle.fill")
                    .foregroundColor(.green)
            } else {
                Image(systemName: "checkmark.circle")
                    .foregroundColor(.secondary)
            }
        default:
            if modelManager.isModelDownloaded(model) {
                Image(systemName: "checkmark.circle")
                    .foregroundColor(.secondary)
            } else {
                Image(systemName: "arrow.down.circle")
                    .foregroundColor(.secondary)
            }
        }
    }

    /// 优先使用 modelStates 中的实时状态，fallback 到 idle
    private var resolvedState: ModelLoadState {
        modelManager.modelStates[model] ?? .idle
    }
}

import AppKit
import SwiftUI
import Combine
import KeyboardShortcuts

// MARK: - KeyboardShortcuts Name (Task 3.1)

extension KeyboardShortcuts.Name {
    static let toggleRecording = Self("toggleRecording", default: .init(.space, modifiers: .option))
}

// MARK: - App Delegate (Task 2.1)

@MainActor
final class AppDelegate: NSObject, NSApplicationDelegate {

    // Core services (Task 2.4 - DI via AppDelegate ownership)
    let appState = AppState()
    /// 提升到顶层，供 VoicePepperApp Scene 在 applicationDidFinishLaunching 前安全访问
    let modelManager = WhisperModelManager()
    private var statusBarManager: StatusBarManager?
    private var audioCaptureService: AudioCaptureService?
    private var transcriptionService: TranscriptionService?
    private var accessibilityMonitor: AccessibilityMonitor?
    private let recordingFileService = RecordingFileService()
    private let diarizationService = FluidAudioDiarizationService()
    private var experimentalWhisperKitService: WhisperKitASRService?
    private var experimentalSpeakerKitService: SpeakerKitDiarizationService?
    private var timelineMerger: TimelineMerger?

    // BLE 录音笔服务
    let bleDeviceManager = BLEDeviceManager()
    private var bleRecorderService: BLERecorderService?

    private var cancellables = Set<AnyCancellable>()
    /// 手动管理偏好设置窗口，避免 .accessory app 中 showSettingsWindow: 不可靠的问题
    private var preferencesWindow: NSWindow?

    // MARK: Lifecycle

    func applicationWillFinishLaunching(_ notification: Notification) {
        terminatePreviousInstances()
    }

    func applicationDidFinishLaunching(_ notification: Notification) {
        // Configure as agent (LSUIElement=YES in Info.plist handles dock hiding)
        NSApp.setActivationPolicy(.accessory)

        // Wire services
        setupServices()
        setupStatusBar()
        setupHotkey()
        setupAccessibilityMonitor()
        setupBindings()
    }

    func applicationWillTerminate(_ notification: Notification) {
        audioCaptureService?.stop()
        bleRecorderService?.stopRealtimeTranscription()
        transcriptionService?.stop()
        // ggml-metal 析构链在 exit() 路径上会触发 GGML_ASSERT 并卡入 UE 状态；
        // _exit() 跳过 C++ 析构，由内核直接回收所有 GPU/文件资源，安全可靠。
        _exit(0)
    }

    // MARK: Single Instance

    /// 终止同名旧实例，确保同一时刻只有一个 VoicePepper 运行。
    /// 策略：先发 SIGTERM 优雅退出，2 秒后若仍存在则 SIGKILL 强杀。
    private func terminatePreviousInstances() {
        let myPID = ProcessInfo.processInfo.processIdentifier
        let myName = ProcessInfo.processInfo.processName

        let stale = NSWorkspace.shared.runningApplications.filter {
            $0.processIdentifier != myPID && $0.localizedName == myName
        }

        guard !stale.isEmpty else { return }

        for app in stale {
            let pid = app.processIdentifier
            NSLog("[AppDelegate] 终止旧实例 PID=\(pid)")
            // 直接 SIGKILL：跳过 ggml-metal 析构路径，避免旧实例卡入 UE 状态
            kill(pid, SIGKILL)
        }

        // 等待 OS 回收旧实例资源（status bar 槽位、Metal 上下文等）
        Thread.sleep(forTimeInterval: 1.0)
    }

    // MARK: Setup

    private func setupServices() {
        let audioService = AudioCaptureService(appState: appState)
        let transcriptionSvc = TranscriptionService(appState: appState, modelManager: modelManager)

        audioCaptureService = audioService
        transcriptionService = transcriptionSvc

        // 注入 RecordingFileService 到 AppState
        appState.recordingFileService = recordingFileService
        recordingFileService.loadRecordings()

        if appState.speechPipelineMode == .experimentalArgmaxOSS {
            let wkService = WhisperKitASRService()
            experimentalWhisperKitService = wkService
            experimentalSpeakerKitService = SpeakerKitDiarizationService()
            timelineMerger = TimelineMerger()
            NSLog("[AppDelegate] Experimental speech pipeline enabled: WhisperKit + SpeakerKit")
            // 注入转录结果回调（Task 2.3）
            Task {
                await wkService.setCallback { [weak self] event in
                    Task { @MainActor [weak self] in
                        self?.handleWhisperKitASREvent(event)
                    }
                }
            }
        }

        // Start model loading immediately on launch
        transcriptionSvc.start()

        // E2E 测试钩子：允许 SwiftUI 按钮通过 AppState 触发录音
        appState.toggleRecordingAction = { [weak self] in
            self?.handleToggleRecording()
        }

        // 偏好设置入口：手动创建 NSWindow，规避 .accessory app 中 showSettingsWindow: 不可靠
        appState.openPreferencesAction = { [weak self] in
            self?.openPreferencesWindow()
        }

        // Connect mic audio → transcription（按 pipeline 模式路由）
        audioService.audioSegmentPublisher
            .sink { [weak self, weak transcriptionSvc] segment in
                guard let self else { return }
                if self.appState.speechPipelineMode == .experimentalArgmaxOSS,
                   let wk = self.experimentalWhisperKitService {
                    Task { await wk.enqueue(segment) }
                } else {
                    transcriptionSvc?.enqueue(segment)
                }
            }
            .store(in: &cancellables)

        // 麦克风录音会话结束 → 持久化
        audioService.sessionEndPublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak self] session in
                guard let self else { return }
                Task { @MainActor in
                    await self.transcriptionService?.waitUntilIdle()
                    let entries = self.appState.entries
                    await self.recordingFileService.save(
                        session: session,
                        transcriptionEntries: entries,
                        diarizationService: self.diarizationService
                    )
                    self.appState.clearSession()
                }
            }
            .store(in: &cancellables)

        // BLE 录音笔服务
        setupBLEServices(transcriptionSvc: transcriptionSvc)
    }

    private func setupBLEServices(transcriptionSvc: TranscriptionService) {
        let bleSvc = BLERecorderService(deviceManager: bleDeviceManager, appState: appState)
        bleRecorderService = bleSvc

        // BLE audio → transcription
        bleSvc.audioSegmentPublisher
            .sink { [weak transcriptionSvc] segment in
                transcriptionSvc?.enqueue(segment)
            }
            .store(in: &cancellables)

        // BLE 音频电平 → AppState
        bleSvc.levelPublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak self] level in
                self?.appState.audioLevel = level
            }
            .store(in: &cancellables)

        // BLE 录音会话结束 → 持久化
        bleSvc.sessionEndPublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak self] session in
                guard let self else { return }
                Task { @MainActor in
                    await self.transcriptionService?.waitUntilIdle()
                    let entries = self.appState.entries
                    await self.recordingFileService.save(
                        session: session,
                        transcriptionEntries: entries,
                        diarizationService: self.diarizationService
                    )
                    self.appState.clearSession()
                }
            }
            .store(in: &cancellables)

        // BLE 状态 → AppState（直接回调）
        NSLog("[AppDelegate] 绑定 BLE 回调到实例 %p", Unmanaged.passUnretained(bleDeviceManager).toOpaque().debugDescription)
        bleDeviceManager.onConnectionStateChanged = { [weak self] state in
            NSLog("[AppDelegate] BLE 状态同步: %@", String(describing: state))
            self?.appState.bleConnectionState = state
        }
        bleDeviceManager.onBatteryLevelChanged = { [weak self] level in
            self?.appState.bleBatteryLevel = level
        }
        bleDeviceManager.onDeviceStatusChanged = { [weak self] status in
            self?.appState.bleDeviceStatus = status
        }
    }

    private func setupStatusBar() {
        statusBarManager = StatusBarManager(appState: appState)
    }

    private func setupHotkey() {
        // Task 3.1 - register ⌥Space via KeyboardShortcuts
        KeyboardShortcuts.onKeyUp(for: .toggleRecording) { [weak self] in
            Task { @MainActor in
                self?.handleToggleRecording()
            }
        }
    }

    private func setupAccessibilityMonitor() {
        // Task 3.3 - poll for accessibility permission changes
        accessibilityMonitor = AccessibilityMonitor { [weak self] granted in
            Task { @MainActor in
                self?.appState.accessibilityPermissionGranted = granted
            }
        }
        accessibilityMonitor?.start()

        // Update initial state
        appState.accessibilityPermissionGranted = AXIsProcessTrusted()
    }

    private func setupBindings() {
        // Keep model load state in sync (TranscriptionService loads async)
        transcriptionService?.modelReadyPublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak self] ready in
                self?.appState.isModelLoaded = ready
            }
            .store(in: &cancellables)

        transcriptionService?.modelErrorPublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak self] error in
                self?.appState.modelLoadError = error
            }
            .store(in: &cancellables)
    }

    // MARK: Recording Control

    func handleToggleRecording() {
        NSLog("[AppDelegate] handleToggleRecording called, source=%@, AXTrusted=%d, isRecording=%d",
              appState.recordingSource.rawValue,
              AXIsProcessTrusted() ? 1 : 0,
              appState.recordingState.isRecording ? 1 : 0)
        // Task 3.2 - check accessibility permission before recording
        guard AXIsProcessTrusted() else {
            NSLog("[AppDelegate] 未获得辅助功能权限，显示提示")
            promptAccessibilityPermission()
            return
        }

        if appState.recordingState.isRecording {
            stopRecording()
        } else {
            startRecording()
        }
    }

    private func startRecording() {
        switch appState.recordingSource {
        case .microphone:
            startMicRecording()
        case .bluetoothRecorder:
            startBLERecording()
        }
    }

    private func stopRecording() {
        switch appState.recordingSource {
        case .microphone:
            audioCaptureService?.stop()
        case .bluetoothRecorder:
            bleRecorderService?.stopRealtimeTranscription()
        }
        appState.stopRecording()
    }

    private func startMicRecording() {
        audioCaptureService?.start { [weak self] error in
            Task { @MainActor in
                if let error {
                    self?.appState.micPermissionDenied = (error == .permissionDenied)
                } else {
                    self?.appState.startRecording()
                }
            }
        }
    }

    private func startBLERecording() {
        guard bleDeviceManager.connectionState == .connected else {
            NSLog("[AppDelegate] 蓝牙录音笔未连接，无法启动录音")
            return
        }
        bleRecorderService?.startRealtimeTranscription()
        appState.startRecording()
    }

    // MARK: WhisperKit ASR Event Handler

    private func handleWhisperKitASREvent(_ event: ASRTranscriptEvent) {
        guard !event.text.isEmpty else { return }
        let duration = event.endTimeSeconds - event.startTimeSeconds
        let entry = TranscriptionEntry(
            text: event.text,
            timestamp: Date(),
            duration: max(duration, 0)
        )
        appState.appendEntry(entry)
    }

    // MARK: Preferences Window

    func openPreferencesWindow() {
        // 若窗口已存在且可见，直接置前
        if let window = preferencesWindow, window.isVisible {
            window.makeKeyAndOrderFront(nil)
            NSApp.activate(ignoringOtherApps: true)
            return
        }

        let view = PreferencesView()
            .environmentObject(appState)
            .environmentObject(modelManager)
            .environmentObject(bleDeviceManager)

        let vc = NSHostingController(rootView: view)
        let window = NSWindow(contentViewController: vc)
        window.title = "偏好设置"
        window.styleMask = [.titled, .closable, .miniaturizable]
        window.setContentSize(NSSize(width: 520, height: 640))
        window.center()
        window.makeKeyAndOrderFront(nil)
        NSApp.activate(ignoringOtherApps: true)

        preferencesWindow = window
    }

    // MARK: Permission Prompts

    private func promptAccessibilityPermission() {
        let options: NSDictionary = [kAXTrustedCheckOptionPrompt.takeRetainedValue(): true]
        AXIsProcessTrustedWithOptions(options)
    }
}

import Foundation
import WhisperKit

actor WhisperKitASRService {
    private let config: WhisperKitConfig
    private var whisperKit: WhisperKit?
    private var pendingTask: Task<Void, Never>?

    private var callback: (@Sendable (ASRTranscriptEvent) -> Void)?

    func setCallback(_ cb: @Sendable @escaping (ASRTranscriptEvent) -> Void) {
        callback = cb
    }

    init(config: WhisperKitConfig? = nil) {
        self.config = config ?? WhisperKitConfig(
            model: "tiny",
            verbose: false,
            load: true,
            download: true
        )
    }

    /// Enqueue a segment for serial transcription. Each call chains after the previous.
    func enqueue(_ segment: AudioSegment) {
        let previous = pendingTask
        pendingTask = Task {
            await previous?.value
            await processSegment(segment)
        }
    }

    private func processSegment(_ segment: AudioSegment) async {
        do {
            let events = try await transcribe(audioSamples: segment.samples)
            let cb = callback
            for event in events where !event.text.isEmpty {
                cb?(event)
            }
        } catch {
            NSLog("[WhisperKitASRService] 转录失败: %@", error.localizedDescription)
        }
    }

    private func prepareIfNeeded() async throws {
        guard whisperKit == nil else { return }
        whisperKit = try await WhisperKit(config)
    }

    private func transcribe(audioSamples: [Float]) async throws -> [ASRTranscriptEvent] {
        try await prepareIfNeeded()
        guard let whisperKit else { return [] }

        let options = DecodingOptions(wordTimestamps: true)
        let results = try await whisperKit.transcribe(audioArray: audioSamples, decodeOptions: options)

        return results.flatMap { result in
            result.segments.map { segment in
                ASRTranscriptEvent(
                    id: UUID(),
                    startTimeSeconds: Double(segment.start),
                    endTimeSeconds: Double(segment.end),
                    text: segment.text.trimmingCharacters(in: .whitespacesAndNewlines),
                    isFinal: true
                )
            }
        }
    }
}

