2	import AppKit
3	
4	// MARK: - Transcription Popover View (Task 6.2)
5	// Main panel: status bar at top, transcript list, action buttons at bottom.
6	
7	struct TranscriptionPopoverView: View {
8	    @EnvironmentObject var appState: AppState
9	
10	    @State private var showClearConfirm = false
11	    @State private var showCopiedFeedback = false
12	    @State private var selectedTab: PopoverTab = .transcription
13	
14	    enum PopoverTab: String, CaseIterable {
15	        case transcription = "转录"
16	        case history = "历史录音"
17	    }
18	
19	    var body: some View {
20	        VStack(spacing: 0) {
21	
22	            // 录音源 + BLE 状态
23	            recordingSourceHeader
24	
25	            Divider()
26	
27	            // Top: Recording status bar (timer + waveform) - Task 6.4
28	            RecordingStatusBar()
29	                .environmentObject(appState)
30	                .accessibilityElement(children: .contain)
31	                .accessibilityIdentifier("recordingStatusBar")
32	
33	            Divider()
34	
35	            // Tab 切换
36	            Picker("", selection: $selectedTab) {
37	                ForEach(PopoverTab.allCases, id: \.self) { tab in
38	                    Text(tab.rawValue).tag(tab)
39	                }
40	            }
41	            .pickerStyle(.segmented)
42	            .padding(.horizontal, 12)
43	            .padding(.vertical, 6)
44	
45	            Divider()
46	
47	            // 内容区
48	            Group {
49	                if selectedTab == .transcription {
50	                    // Middle: Transcript list (scrollable) - Task 6.3
51	                    TranscriptionListView()
52	                        .environmentObject(appState)
53	                        .frame(minHeight: 280)
54	                } else {
55	                    // 历史录音列表
56	                    if let service = appState.recordingFileService {
57	                        RecordingHistoryView(
58	                            service: service,
59	                            currentlyPlayingId: Binding(
60	                                get: { appState.currentlyPlayingId },
61	                                set: { appState.currentlyPlayingId = $0 }
62	                            )
63	                        )
64	                        .frame(minHeight: 280)
65	                    } else {
66	                        Text("录音服务未就绪")
67	                            .foregroundColor(.secondary)
68	                            .frame(maxWidth: .infinity, maxHeight: .infinity)
69	                    }
70	                }
71	            }
72	
73	            Divider()
74	
75	            // Bottom: Action bar
76	            actionBar
77	        }
78	        .frame(width: 400, height: 460)
79	        .background(Color(NSColor.windowBackgroundColor))
80	        // .contain 保留子元素各自的 accessibilityIdentifier，避免 SwiftUI 平铺时被父 id 覆盖
81	        .accessibilityElement(children: .contain)
82	        .accessibilityIdentifier("transcriptionPopover")
83	        // E2E 测试钩子：零尺寸隐藏按钮，通过 AX 触发录音切换
84	        .overlay(alignment: .topLeading) {
85	            Button("") {
86	                NSLog("[TestButton] testToggleRecordingButton pressed")
87	                appState.toggleRecordingAction?()
88	            }
89	            .frame(width: 1, height: 1)
90	            .opacity(0.01)
91	            .accessibilityLabel("Toggle Recording")
92	            .accessibilityIdentifier("testToggleRecordingButton")
93	        }
94	    }
95	
96	    // MARK: Recording Source Header
97	
98	    private var recordingSourceHeader: some View {
99	        HStack(spacing: 8) {
100	            // 录音源选择
101	            Picker("", selection: $appState.recordingSource) {
102	                ForEach(RecordingSource.allCases) { source in
103	                    Label(source.displayName, systemImage: source == .microphone ? "mic" : "antenna.radiowaves.left.and.right")
104	                        .tag(source)
105	                }
106	            }
107	            .pickerStyle(.segmented)
108	            .frame(width: 200)
109	
110	            Spacer()
111	
112	            // BLE 状态指示（仅蓝牙模式显示）
113	            if appState.recordingSource == .bluetoothRecorder {
114	                bleStatusIndicator
115	            }
116	        }
117	        .padding(.horizontal, 12)
118	        .padding(.vertical, 6)
119	    }
120	
121	    @ViewBuilder
122	    private var bleStatusIndicator: some View {
123	        HStack(spacing: 4) {
124	            // 连接状态圆点
125	            Circle()
126	                .fill(bleConnectionColor)
127	                .frame(width: 8, height: 8)
128	
129	            Text(bleConnectionText)
130	                .font(.caption2)
131	                .foregroundColor(.secondary)
132	
133	            // 电量指示
134	            if let battery = appState.bleBatteryLevel {
135	                Divider().frame(height: 12)
136	                if battery == 110 {
137	                    Image(systemName: "battery.100.bolt")
138	                        .font(.caption2)
139	                        .foregroundColor(.green)
140	                } else {
141	                    Image(systemName: batteryIcon(battery))
142	                        .font(.caption2)
143	                        .foregroundColor(battery <= 20 ? .red : .secondary)
144	                    Text("\(battery)%")
145	                        .font(.caption2)
146	                        .foregroundColor(.secondary)
147	                }
148	            }
149	        }
150	        .accessibilityIdentifier("bleStatusIndicator")
151	    }
