                    .foregroundColor(.secondary)
                    .multilineTextAlignment(.center)
            } else {
                Text("按下快捷键开始录音")
                    .font(.callout)
                    .foregroundColor(.secondary)

                Text("默认：⌥ Space")
                    .font(.caption)
                    .foregroundColor(.secondary)
                    .padding(4)
                    .background(Color(NSColor.controlBackgroundColor))
                    .cornerRadius(4)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .padding()
        .accessibilityIdentifier("emptyTranscriptionView")
    }
}

