                Text("\(transcriptionCount) 条")
                    .font(.caption2)
                    .foregroundColor(.secondary)
            }

            // Copy all (Task 6.6)
            Button {
                copyAll()
            } label: {
                Label(showCopiedFeedback ? "已复制" : "复制全部", systemImage: "doc.on.doc")
                    .font(.caption)
            }
            .buttonStyle(.bordered)
            .disabled(transcriptionIsEmpty)
            .accessibilityIdentifier("copyAllButton")
        }
        .padding(.horizontal, 16)
        .padding(.vertical, 8)
    }

    // MARK: Helpers

    private var transcriptionIsEmpty: Bool {
        appState.speechPipelineMode == .experimentalArgmaxOSS
            ? appState.realtimeChunks.isEmpty
            : appState.entries.isEmpty
    }

    private var transcriptionCount: Int {
        appState.speechPipelineMode == .experimentalArgmaxOSS
            ? appState.realtimeChunks.count
            : appState.entries.count
    }

    // MARK: Copy Action (Task 6.6)

    private func copyAll() {
        NSPasteboard.general.clearContents()
        let text: String
        if appState.speechPipelineMode == .experimentalArgmaxOSS {
            text = appState.realtimeChunks
                .map { "[\($0.speakerLabel ?? "?")] \($0.text)" }
                .joined(separator: "\n")
        } else {
            text = appState.allTranscriptionText
        }
        NSPasteboard.general.setString(text, forType: .string)

        withAnimation { showCopiedFeedback = true }
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.2) {
            withAnimation { self.showCopiedFeedback = false }
        }
    }
}

import SwiftUI

// MARK: - Transcription List

struct TranscriptionListView: View {
    @EnvironmentObject var appState: AppState

    var body: some View {
        Group {
            if appState.speechPipelineMode == .experimentalArgmaxOSS {
                RealtimeChunkListView()
                    .environmentObject(appState)
            } else {
                LegacyEntryListView()
                    .environmentObject(appState)
            }
        }
    }
}

// MARK: - Legacy Entry List (whisper.cpp 模式)

private struct LegacyEntryListView: View {
    @EnvironmentObject var appState: AppState

    var body: some View {
        Group {
            if appState.entries.isEmpty {
                EmptyTranscriptionView()
            } else {
                ScrollViewReader { proxy in
                    ScrollView {
                        LazyVStack(alignment: .leading, spacing: 8) {
                            ForEach(appState.entries) { entry in
                                EntryRow(entry: entry)
                                    .id(entry.id)
                                    .accessibilityIdentifier("transcriptionEntry-\(entry.id)")
                            }
                        }
                        .padding(.horizontal, 16)
                        .padding(.vertical, 8)
                    }
                    .accessibilityIdentifier("transcriptionScrollView")
                    .onChange(of: appState.entries.count) {
                        if let lastId = appState.entries.last?.id {
                            withAnimation(.easeOut(duration: 0.2)) {
                                proxy.scrollTo(lastId, anchor: .bottom)
                            }
                        }
                    }
                }
            }
        }
    }
}

// MARK: - Realtime Chunk List (实验性模式)

private struct RealtimeChunkListView: View {
    @EnvironmentObject var appState: AppState

    var body: some View {
        Group {
            if appState.realtimeChunks.isEmpty {
                EmptyTranscriptionView()
            } else {
                ScrollViewReader { proxy in
                    ScrollView {
                        LazyVStack(alignment: .leading, spacing: 8) {
                            ForEach(appState.realtimeChunks) { chunk in
                                ChunkRowView(chunk: chunk)
                                    .id(chunk.id)
                                    .accessibilityIdentifier("transcriptionEntry-\(chunk.id)")
                            }
                        }
                        .padding(.horizontal, 16)
                        .padding(.vertical, 8)
                    }
                    .accessibilityIdentifier("transcriptionScrollView")
                    .onChange(of: appState.realtimeChunks.count) {
                        if let lastId = appState.realtimeChunks.last?.id {
                            withAnimation(.easeOut(duration: 0.2)) {
                                proxy.scrollTo(lastId, anchor: .bottom)
                            }
                        }
                    }
                }
            }
        }
    }
}

// MARK: - Chunk Row (实验性模式带 speaker badge)

struct ChunkRowView: View {
    let chunk: RealtimeTranscriptChunk

    var body: some View {
        HStack(alignment: .top, spacing: 8) {
            Text(chunk.speakerLabel ?? "?")
                .font(.caption2)
                .fontWeight(.semibold)
                .foregroundColor(.white)
                .padding(.horizontal, 5)
                .padding(.vertical, 2)
                .background(speakerColor)
                .cornerRadius(4)
                .fixedSize()

            VStack(alignment: .leading, spacing: 2) {
                Text(chunk.text)
                    .font(.body)
                    .textSelection(.enabled)
                    .fixedSize(horizontal: false, vertical: true)
                    .foregroundColor(chunk.isFinal ? .primary : .secondary)

                Text(String(format: "%.1fs – %.1fs", chunk.startTimeSeconds, chunk.endTimeSeconds))
                    .font(.caption2)
                    .foregroundColor(.secondary)
            }
        }
        .padding(8)
        .frame(maxWidth: .infinity, alignment: .leading)
        .background(Color(NSColor.controlBackgroundColor))
        .cornerRadius(6)
    }

    private var speakerColor: Color {
        switch chunk.speakerLabel {
        case "S0": return .blue
        case "S1": return Color.orange
        case "S2": return Color.purple
        case "S3": return Color.green
        case "S4": return Color.pink
        case nil:  return Color.gray
        default:   return Color.indigo
        }
    }
}

// MARK: - Entry Row (Legacy)

private struct EntryRow: View {
    let entry: TranscriptionEntry

    var body: some View {
        VStack(alignment: .leading, spacing: 2) {
            Text(entry.text)
                .font(.body)
                .textSelection(.enabled)
                .fixedSize(horizontal: false, vertical: true)

            Text(entry.formattedTimestamp)
                .font(.caption2)
                .foregroundColor(.secondary)
        }
        .padding(8)
        .frame(maxWidth: .infinity, alignment: .leading)
        .background(Color(NSColor.controlBackgroundColor))
        .cornerRadius(6)
    }
}

// MARK: - Empty State

struct EmptyTranscriptionView: View {
    @EnvironmentObject var appState: AppState

    var body: some View {
        VStack(spacing: 12) {
            Image(systemName: "mic.slash")
                .font(.system(size: 32))
                .foregroundColor(.secondary)
                .accessibilityIdentifier("emptyStateIcon")

            if let error = appState.modelLoadError {
                Text("模型加载失败")
                    .font(.headline)
                Text(error)
                    .font(.caption)
                    .foregroundColor(.red)
                    .multilineTextAlignment(.center)
            } else if !appState.isModelLoaded {
                Text("正在加载 Whisper 模型...")
                    .font(.callout)
                    .foregroundColor(.secondary)
                ProgressView()
                    .scaleEffect(0.8)
            } else if appState.micPermissionDenied {
                Text("麦克风权限被拒绝")
                    .font(.headline)
                Text("请在系统设置 > 隐私与安全 > 麦克风 中允许 VoicePepper")
                    .font(.caption)
                    .foregroundColor(.secondary)
                    .multilineTextAlignment(.center)
            } else {
                Text("按下快捷键开始录音")
                    .font(.callout)
                    .foregroundColor(.secondary)

                Text("默认：⌥ Space")
                    .font(.caption)
                    .foregroundColor(.secondary)
                    .padding(4)
                    .background(Color(NSColor.controlBackgroundColor))
                    .cornerRadius(4)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .padding()
        .accessibilityIdentifier("emptyTranscriptionView")
    }
}

import AVFoundation
import Foundation

// MARK: - Recording Item

struct RecordingItem: Identifiable, Equatable {
    let id: UUID
    let url: URL
    let duration: TimeInterval   // 秒
    let createdAt: Date
    let transcriptionURL: URL?   // 配对的 .txt 转录文本文件
    let transcriptJSONURL: URL?  // 配对的结构化 transcript JSON 文件

    var formattedDate: String {
        let f = DateFormatter()
        f.dateStyle = .short
        f.timeStyle = .medium
        return f.string(from: createdAt)
    }

    var formattedDuration: String {
        let total = Int(duration)
        let m = total / 60
        let s = total % 60
        return String(format: "%d:%02d", m, s)
    }

    /// 按需从配对的 .txt 文件读取转录文本
    var transcriptionText: String? {
        guard let txtURL = transcriptionURL else { return nil }
        return try? String(contentsOf: txtURL, encoding: .utf8)
    }

    var speakerAttributedTranscript: SpeakerAttributedTranscriptDocument? {
        guard let jsonURL = transcriptJSONURL else { return nil }
        return RecordingFileService.loadTranscriptDocument(from: jsonURL)
    }

    var preferredTranscriptionText: String? {
        if let structured = speakerAttributedTranscript?.formattedText, !structured.isEmpty {
            return structured
        }
        return transcriptionText
    }

    static func == (lhs: RecordingItem, rhs: RecordingItem) -> Bool {
        lhs.id == rhs.id
    }
}

// MARK: - Recording File Service

/// 负责将录音会话 PCM 样本持久化为 WAV 文件，并管理历史录音列表。
/// 使用 PCM 直写（无需 AAC 编码），AVAudioPlayer 原生支持 WAV 回放。
@MainActor
final class RecordingFileService: ObservableObject {

    // MARK: 存储目录

    /// ~/Library/Application Support/VoicePepper/Recordings/
    var storageDirectory: URL {
        let appSupport = FileManager.default.urls(
            for: .applicationSupportDirectory, in: .userDomainMask
        ).first!
        let dir = appSupport.appendingPathComponent("VoicePepper/Recordings", isDirectory: true)
        if !FileManager.default.fileExists(atPath: dir.path) {
            try? FileManager.default.createDirectory(at: dir, withIntermediateDirectories: true)
        }
        return dir
    }

    // MARK: 列表

    @Published private(set) var recordings: [RecordingItem] = []

    func loadRecordings() {
        let dir = storageDirectory
        do {
            let urls = try FileManager.default.contentsOfDirectory(
                at: dir,
                includingPropertiesForKeys: [.contentModificationDateKey],
                options: .skipsHiddenFiles
            )
            recordings = urls
                // 同时支持 wav（新格式）和旧的空 m4a 文件（排除零字节文件）
                .filter {
                    let ext = $0.pathExtension.lowercased()
                    guard ext == "wav" || ext == "m4a" else { return false }
                    let size = (try? FileManager.default.attributesOfItem(atPath: $0.path)[.size] as? Int) ?? 0
                    return size > 0
                }
                .compactMap { url -> RecordingItem? in
                    let attrs = try? url.resourceValues(forKeys: [.contentModificationDateKey])
                    let createdAt = attrs?.contentModificationDate ?? Date()
                    let duration = Self.durationOf(url: url)
                    let txtURL = Self.txtURL(for: url)
                    let jsonURL = Self.transcriptJSONURL(for: url)
                    let hasTranscription = FileManager.default.fileExists(atPath: txtURL.path)
                    let hasTranscriptJSON = FileManager.default.fileExists(atPath: jsonURL.path)
                    return RecordingItem(
                        id: UUID(),
                        url: url,
                        duration: duration,
                        createdAt: createdAt,
                        transcriptionURL: hasTranscription ? txtURL : nil,
                        transcriptJSONURL: hasTranscriptJSON ? jsonURL : nil
                    )
                }
                .sorted { $0.createdAt > $1.createdAt }
        } catch {
            NSLog("[RecordingFileService] 无法枚举录音目录: %@", error.localizedDescription)
        }
    }

    // MARK: 保存

    /// 将整个会话的完整 PCM 样本异步写为一个 WAV 文件（合并所有 VAD 段）。
    /// 同时将转录条目保存为同名 .txt 文件，并尽力生成结构化 transcript JSON。
    func save(
        session: RecordingSessionData,
        transcriptionEntries: [TranscriptionEntry] = [],
        diarizationService: FluidAudioDiarizationService? = nil,
        sampleRate: Double = 16000
    ) async {
        guard !session.samples.isEmpty else { return }
        let outputURL = makeOutputURL()
        do {
            let duration = try await Task.detached(priority: .utility) {
                try Self.writeWAV(samples: session.samples, sampleRate: sampleRate, to: outputURL)
            }.value

            var txtURL: URL? = nil
            if !transcriptionEntries.isEmpty {
                txtURL = Self.txtURL(for: outputURL)
                let text = transcriptionEntries.map { entry in
                    let f = DateFormatter()
                    f.dateFormat = "HH:mm:ss"
                    return "[\(f.string(from: entry.timestamp))] \(entry.text)"
                }.joined(separator: "\n")
                try text.write(to: txtURL!, atomically: true, encoding: .utf8)
            }

            var transcriptJSONURL: URL? = nil
            if let diarizationService, !transcriptionEntries.isEmpty {
                do {
                    if let transcript = try await diarizationService.buildTranscript(
                        recordingURL: outputURL,
                        transcriptionEntries: transcriptionEntries,
                        session: session
                    ) {
                        transcriptJSONURL = Self.transcriptJSONURL(for: outputURL)
                        try Self.writeTranscriptDocument(transcript, to: transcriptJSONURL!)
                    }
                } catch {
                    NSLog("[RecordingFileService] diarization 失败，回退纯文本: %@", error.localizedDescription)
                }
            }

            let item = RecordingItem(
                id: UUID(),
                url: outputURL,
                duration: duration,
                createdAt: Date(),
                transcriptionURL: txtURL,
                transcriptJSONURL: transcriptJSONURL
            )
            recordings.insert(item, at: 0)
            NSLog("[RecordingFileService] 已保存: %@ (%.1fs)", outputURL.lastPathComponent, duration)
        } catch {
            NSLog("[RecordingFileService] 写盘失败: %@", error.localizedDescription)
        }
    }

    /// 实验性模式：用 TimelineMerger snapshot 的 RealtimeTranscriptChunk 列表落盘。
    func saveWithRealtimeChunks(
        session: RecordingSessionData,
        chunks: [RealtimeTranscriptChunk],
        sampleRate: Double = 16000
    ) async {
        guard !session.samples.isEmpty else { return }
        let outputURL = makeOutputURL()
        do {
            let duration = try await Task.detached(priority: .utility) {
                try Self.writeWAV(samples: session.samples, sampleRate: sampleRate, to: outputURL)
            }.value

            var txtURL: URL? = nil
            if !chunks.isEmpty {
                txtURL = Self.txtURL(for: outputURL)
                let text = chunks.map { "[\($0.speakerLabel ?? "?")] \($0.text)" }.joined(separator: "\n")
                try text.write(to: txtURL!, atomically: true, encoding: .utf8)
            }

            var transcriptJSONURL: URL? = nil
            if !chunks.isEmpty {
                let attrChunks = chunks.map { chunk in
                    SpeakerAttributedTranscriptChunk(
                        text: chunk.text,
                        timestamp: session.startedAt.addingTimeInterval(chunk.startTimeSeconds),
                        relativeTimeSeconds: chunk.startTimeSeconds,
                        speakerLabel: chunk.speakerLabel,
                        startTimeSeconds: chunk.startTimeSeconds,
                        endTimeSeconds: chunk.endTimeSeconds
                    )
                }
                let speakerLabels = Set(chunks.compactMap(\.speakerLabel))
                let diarizationSegments = speakerLabels.map { label -> SpeakerDiarizationSegment in
                    let matching = chunks.filter { $0.speakerLabel == label }
                    let start = matching.map(\.startTimeSeconds).min() ?? 0
                    let end = matching.map(\.endTimeSeconds).max() ?? 0
                    return SpeakerDiarizationSegment(speakerLabel: label, startTimeSeconds: start, endTimeSeconds: end)
                }
                let document = SpeakerAttributedTranscriptDocument(
                    fullText: chunks.map(\.text).joined(separator: "\n"),
                    chunks: attrChunks,
                    diarizationSegments: diarizationSegments,
                    engineMetadata: SpeechEngineMetadata(asrEngine: "whisperkit", diarizationEngine: "speakerkit")
                )
                transcriptJSONURL = Self.transcriptJSONURL(for: outputURL)
                try Self.writeTranscriptDocument(document, to: transcriptJSONURL!)
            }

            let item = RecordingItem(
                id: UUID(),
                url: outputURL,
                duration: duration,
                createdAt: Date(),
                transcriptionURL: txtURL,
                transcriptJSONURL: transcriptJSONURL
            )
            recordings.insert(item, at: 0)
            NSLog("[RecordingFileService] 已保存(experimental): %@ (%.1fs, %d chunks)", outputURL.lastPathComponent, duration, chunks.count)
        } catch {
            NSLog("[RecordingFileService] 写盘失败: %@", error.localizedDescription)
        }
    }

    /// 根据录音文件 URL 推导配对的 .txt 文件 URL
    private static func txtURL(for recordingURL: URL) -> URL {
        let name = recordingURL.deletingPathExtension().lastPathComponent
        return recordingURL.deletingLastPathComponent().appendingPathComponent("\(name).txt")
    }

    static func transcriptJSONURL(for recordingURL: URL) -> URL {
        let name = recordingURL.deletingPathExtension().lastPathComponent
        return recordingURL.deletingLastPathComponent().appendingPathComponent("\(name).json")
    }

    // MARK: 删除

    func delete(item: RecordingItem) {
        do {
            try FileManager.default.removeItem(at: item.url)
        } catch {
            NSLog("[RecordingFileService] 删除失败: %@", error.localizedDescription)
        }
        // 同步删除配对的转录文本文件
        if let txtURL = item.transcriptionURL {
            try? FileManager.default.removeItem(at: txtURL)
        }
        if let jsonURL = item.transcriptJSONURL {
            try? FileManager.default.removeItem(at: jsonURL)
        }
        recordings.removeAll { $0.id == item.id }
    }

    // MARK: 私有工具

    private func makeOutputURL() -> URL {
        let formatter = DateFormatter()
        formatter.dateFormat = "yyyyMMdd_HHmmss"
        let name = "Recording_\(formatter.string(from: Date())).wav"
        return storageDirectory.appendingPathComponent(name)
    }

    private static func durationOf(url: URL) -> TimeInterval {
        guard let audioFile = try? AVAudioFile(forReading: url) else { return 0 }
        let sampleRate = audioFile.processingFormat.sampleRate
        guard sampleRate > 0 else { return 0 }
        return Double(audioFile.length) / sampleRate
    }

    private static func writeTranscriptDocument(
        _ transcript: SpeakerAttributedTranscriptDocument,
        to url: URL
    ) throws {
        let encoder = JSONEncoder()
        encoder.outputFormatting = [.prettyPrinted, .sortedKeys]
        encoder.dateEncodingStrategy = .iso8601
        let data = try encoder.encode(transcript)
        try data.write(to: url, options: .atomic)
    }

    nonisolated static func loadTranscriptDocument(from url: URL) -> SpeakerAttributedTranscriptDocument? {
        guard let data = try? Data(contentsOf: url) else { return nil }
        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        return try? decoder.decode(SpeakerAttributedTranscriptDocument.self, from: data)
    }

    // MARK: 写盘（nonisolated，在后台线程调用）

    /// 将 Float32 PCM 样本写入 WAV 文件，返回实际时长（秒）。
    /// WAV 格式直写，无需 AAC 编码，兼容所有 macOS 版本。
    private nonisolated static func writeWAV(samples: [Float], sampleRate: Double, to outputURL: URL) throws -> TimeInterval {
        let wavSettings: [String: Any] = [
            AVFormatIDKey: kAudioFormatLinearPCM,
            AVSampleRateKey: sampleRate,
            AVNumberOfChannelsKey: 1,
            AVLinearPCMBitDepthKey: 32,
            AVLinearPCMIsFloatKey: true,
            AVLinearPCMIsBigEndianKey: false,
            AVLinearPCMIsNonInterleaved: false
        ]

        let pcmFormat = AVAudioFormat(
            commonFormat: .pcmFormatFloat32,
            sampleRate: sampleRate,
            channels: 1,
            interleaved: false
        )!

        let audioFile = try AVAudioFile(forWriting: outputURL, settings: wavSettings)

        let chunkSize = 65_536
        var offset = 0

        while offset < samples.count {
            let end = min(offset + chunkSize, samples.count)
            let chunkCount = end - offset

            guard let buffer = AVAudioPCMBuffer(
                pcmFormat: pcmFormat,
                frameCapacity: AVAudioFrameCount(chunkCount)
            ) else { break }

            buffer.frameLength = AVAudioFrameCount(chunkCount)
            if let channelData = buffer.floatChannelData {
                samples.withUnsafeBufferPointer { ptr in
                    channelData[0].update(from: ptr.baseAddress! + offset, count: chunkCount)
                }
            }

            try audioFile.write(from: buffer)
            offset = end
        }

        return Double(samples.count) / sampleRate
    }
}

import AppKit
import SwiftUI
import Combine
import KeyboardShortcuts

// MARK: - KeyboardShortcuts Name (Task 3.1)

extension KeyboardShortcuts.Name {
    static let toggleRecording = Self("toggleRecording", default: .init(.space, modifiers: .option))
}

// MARK: - App Delegate (Task 2.1)

@MainActor
final class AppDelegate: NSObject, NSApplicationDelegate {

    // Core services (Task 2.4 - DI via AppDelegate ownership)
    let appState = AppState()
    /// 提升到顶层，供 VoicePepperApp Scene 在 applicationDidFinishLaunching 前安全访问
    let modelManager = WhisperModelManager()
    private var statusBarManager: StatusBarManager?
    private var audioCaptureService: AudioCaptureService?
    private var transcriptionService: TranscriptionService?
    private var accessibilityMonitor: AccessibilityMonitor?
    private let recordingFileService = RecordingFileService()
    private let diarizationService = FluidAudioDiarizationService()
    private var experimentalWhisperKitService: WhisperKitASRService?
    private var experimentalSpeakerKitService: SpeakerKitDiarizationService?
    private var timelineMerger: TimelineMerger?

    // BLE 录音笔服务
    let bleDeviceManager = BLEDeviceManager()
    private var bleRecorderService: BLERecorderService?

    private var cancellables = Set<AnyCancellable>()
    /// 手动管理偏好设置窗口，避免 .accessory app 中 showSettingsWindow: 不可靠的问题
    private var preferencesWindow: NSWindow?

    // MARK: Lifecycle

    func applicationWillFinishLaunching(_ notification: Notification) {
        terminatePreviousInstances()
    }

    func applicationDidFinishLaunching(_ notification: Notification) {
        // Configure as agent (LSUIElement=YES in Info.plist handles dock hiding)
        NSApp.setActivationPolicy(.accessory)

        // Wire services
        setupServices()
        setupStatusBar()
        setupHotkey()
        setupAccessibilityMonitor()
        setupBindings()
    }

    func applicationWillTerminate(_ notification: Notification) {
        audioCaptureService?.stop()
        bleRecorderService?.stopRealtimeTranscription()
        transcriptionService?.stop()
        // ggml-metal 析构链在 exit() 路径上会触发 GGML_ASSERT 并卡入 UE 状态；
        // _exit() 跳过 C++ 析构，由内核直接回收所有 GPU/文件资源，安全可靠。
        _exit(0)
    }

    // MARK: Single Instance

    /// 终止同名旧实例，确保同一时刻只有一个 VoicePepper 运行。
    /// 策略：先发 SIGTERM 优雅退出，2 秒后若仍存在则 SIGKILL 强杀。
    private func terminatePreviousInstances() {
        let myPID = ProcessInfo.processInfo.processIdentifier
        let myName = ProcessInfo.processInfo.processName

        let stale = NSWorkspace.shared.runningApplications.filter {
            $0.processIdentifier != myPID && $0.localizedName == myName
        }

        guard !stale.isEmpty else { return }

        for app in stale {
            let pid = app.processIdentifier
            NSLog("[AppDelegate] 终止旧实例 PID=\(pid)")
            // 直接 SIGKILL：跳过 ggml-metal 析构路径，避免旧实例卡入 UE 状态
            kill(pid, SIGKILL)
        }

        // 等待 OS 回收旧实例资源（status bar 槽位、Metal 上下文等）
        Thread.sleep(forTimeInterval: 1.0)
    }

    // MARK: Setup

    private func setupServices() {
        let audioService = AudioCaptureService(appState: appState)
        let transcriptionSvc = TranscriptionService(appState: appState, modelManager: modelManager)

        audioCaptureService = audioService
        transcriptionService = transcriptionSvc

        // 注入 RecordingFileService 到 AppState
        appState.recordingFileService = recordingFileService
        recordingFileService.loadRecordings()

        if appState.speechPipelineMode == .experimentalArgmaxOSS {
            let wkService = WhisperKitASRService()
            let skService = SpeakerKitDiarizationService()
            let merger = TimelineMerger()
            experimentalWhisperKitService = wkService
            experimentalSpeakerKitService = skService
            timelineMerger = merger
            NSLog("[AppDelegate] Experimental speech pipeline enabled: WhisperKit + SpeakerKit")
            // 注入 WhisperKit 转录回调 → TimelineMerger → AppState.realtimeChunks
            Task {
                await wkService.setCallback { [weak self] event in
                    Task { @MainActor [weak self] in
                        self?.handleWhisperKitASREvent(event)
                    }
                }
            }
            // 注入 SpeakerKit diarization 回调 → TimelineMerger → AppState.realtimeChunks
            Task {
                await skService.setCallback { [weak self] events in
                    Task { @MainActor [weak self] in
                        guard let self else { return }
                        for event in events {
                            let chunks = await merger.applySpeakerEvent(event)
                            self.appState.updateRealtimeChunks(chunks)
                        }
                    }
                }
            }
        }

        // Start model loading immediately on launch
        transcriptionSvc.start()

        // E2E 测试钩子：允许 SwiftUI 按钮通过 AppState 触发录音
        appState.toggleRecordingAction = { [weak self] in
            self?.handleToggleRecording()
        }

        // 偏好设置入口：手动创建 NSWindow，规避 .accessory app 中 showSettingsWindow: 不可靠
        appState.openPreferencesAction = { [weak self] in
            self?.openPreferencesWindow()
        }

        // Connect mic audio → transcription（按 pipeline 模式路由）
        audioService.audioSegmentPublisher
            .sink { [weak self, weak transcriptionSvc] segment in
                guard let self else { return }
                if self.appState.speechPipelineMode == .experimentalArgmaxOSS,
                   let wk = self.experimentalWhisperKitService {
                    Task { await wk.enqueue(segment) }
                    if let sk = self.experimentalSpeakerKitService {
                        Task { await sk.enqueue(segment) }
                    }
                } else {
                    transcriptionSvc?.enqueue(segment)
                }
            }
            .store(in: &cancellables)

        // 麦克风录音会话结束 → 持久化
        audioService.sessionEndPublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak self] session in
                guard let self else { return }
                Task { @MainActor in
                    if self.appState.speechPipelineMode == .experimentalArgmaxOSS,
                       let merger = self.timelineMerger {
                        let chunks = await merger.snapshot()
                        await self.recordingFileService.saveWithRealtimeChunks(
                            session: session,
                            chunks: chunks
                        )
                    } else {
                        await self.transcriptionService?.waitUntilIdle()
                        let entries = self.appState.entries
                        await self.recordingFileService.save(
                            session: session,
                            transcriptionEntries: entries,
                            diarizationService: self.diarizationService
                        )
                    }
                    self.appState.clearSession()
                }
            }
            .store(in: &cancellables)

        // BLE 录音笔服务
        setupBLEServices(transcriptionSvc: transcriptionSvc)
    }

    private func setupBLEServices(transcriptionSvc: TranscriptionService) {
        let bleSvc = BLERecorderService(deviceManager: bleDeviceManager, appState: appState)
        bleRecorderService = bleSvc

        // BLE audio → transcription
        bleSvc.audioSegmentPublisher
            .sink { [weak transcriptionSvc] segment in
                transcriptionSvc?.enqueue(segment)
            }
            .store(in: &cancellables)

        // BLE 音频电平 → AppState
        bleSvc.levelPublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak self] level in
                self?.appState.audioLevel = level
            }
            .store(in: &cancellables)

        // BLE 录音会话结束 → 持久化
        bleSvc.sessionEndPublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak self] session in
                guard let self else { return }
                Task { @MainActor in
                    await self.transcriptionService?.waitUntilIdle()
                    let entries = self.appState.entries
                    await self.recordingFileService.save(
                        session: session,
                        transcriptionEntries: entries,
                        diarizationService: self.diarizationService
                    )
                    self.appState.clearSession()
                }
            }
            .store(in: &cancellables)

        // BLE 状态 → AppState（直接回调）
        NSLog("[AppDelegate] 绑定 BLE 回调到实例 %p", Unmanaged.passUnretained(bleDeviceManager).toOpaque().debugDescription)
        bleDeviceManager.onConnectionStateChanged = { [weak self] state in
            NSLog("[AppDelegate] BLE 状态同步: %@", String(describing: state))
            self?.appState.bleConnectionState = state
        }
        bleDeviceManager.onBatteryLevelChanged = { [weak self] level in
            self?.appState.bleBatteryLevel = level
        }
        bleDeviceManager.onDeviceStatusChanged = { [weak self] status in
            self?.appState.bleDeviceStatus = status
        }
    }

    private func setupStatusBar() {
        statusBarManager = StatusBarManager(appState: appState)
    }

    private func setupHotkey() {
        // Task 3.1 - register ⌥Space via KeyboardShortcuts
        KeyboardShortcuts.onKeyUp(for: .toggleRecording) { [weak self] in
            Task { @MainActor in
                self?.handleToggleRecording()
            }
        }
    }

    private func setupAccessibilityMonitor() {
        // Task 3.3 - poll for accessibility permission changes
        accessibilityMonitor = AccessibilityMonitor { [weak self] granted in
            Task { @MainActor in
                self?.appState.accessibilityPermissionGranted = granted
            }
        }
        accessibilityMonitor?.start()

        // Update initial state
        appState.accessibilityPermissionGranted = AXIsProcessTrusted()
    }

    private func setupBindings() {
        // Keep model load state in sync (TranscriptionService loads async)
        transcriptionService?.modelReadyPublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak self] ready in
                self?.appState.isModelLoaded = ready
            }
            .store(in: &cancellables)

        transcriptionService?.modelErrorPublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak self] error in
                self?.appState.modelLoadError = error
            }
            .store(in: &cancellables)
    }

    // MARK: Recording Control

    func handleToggleRecording() {
        NSLog("[AppDelegate] handleToggleRecording called, source=%@, AXTrusted=%d, isRecording=%d",
              appState.recordingSource.rawValue,
              AXIsProcessTrusted() ? 1 : 0,
              appState.recordingState.isRecording ? 1 : 0)
        // Task 3.2 - check accessibility permission before recording
        guard AXIsProcessTrusted() else {
            NSLog("[AppDelegate] 未获得辅助功能权限，显示提示")
            promptAccessibilityPermission()
            return
        }

        if appState.recordingState.isRecording {
            stopRecording()
        } else {
            startRecording()
        }
    }

    private func startRecording() {
        switch appState.recordingSource {
        case .microphone:
            startMicRecording()
        case .bluetoothRecorder:
            startBLERecording()
        }
    }

    private func stopRecording() {
        switch appState.recordingSource {
        case .microphone:
            audioCaptureService?.stop()
        case .bluetoothRecorder:
            bleRecorderService?.stopRealtimeTranscription()
        }
        appState.stopRecording()
    }

    private func startMicRecording() {
        audioCaptureService?.start { [weak self] error in
            Task { @MainActor in
                if let error {
                    self?.appState.micPermissionDenied = (error == .permissionDenied)
                } else {
                    self?.appState.startRecording()
                }
            }
        }
    }

    private func startBLERecording() {
        guard bleDeviceManager.connectionState == .connected else {
            NSLog("[AppDelegate] 蓝牙录音笔未连接，无法启动录音")
            return
        }
        bleRecorderService?.startRealtimeTranscription()
        appState.startRecording()
    }

    // MARK: WhisperKit ASR Event Handler

    private func handleWhisperKitASREvent(_ event: ASRTranscriptEvent) {
        guard !event.text.isEmpty else { return }
        if let merger = timelineMerger {
            Task {
                let chunks = await merger.applyASREvent(event, source: .microphone)
                await MainActor.run { self.appState.updateRealtimeChunks(chunks) }
            }
        } else {
            let duration = event.endTimeSeconds - event.startTimeSeconds
            let entry = TranscriptionEntry(
                text: event.text,
                timestamp: Date(),
                duration: max(duration, 0)
            )
            appState.appendEntry(entry)
        }
    }

    // MARK: Preferences Window

    func openPreferencesWindow() {
        // 若窗口已存在且可见，直接置前
        if let window = preferencesWindow, window.isVisible {
            window.makeKeyAndOrderFront(nil)
            NSApp.activate(ignoringOtherApps: true)
            return
        }

        let view = PreferencesView()
            .environmentObject(appState)
            .environmentObject(modelManager)
            .environmentObject(bleDeviceManager)

        let vc = NSHostingController(rootView: view)
        let window = NSWindow(contentViewController: vc)
        window.title = "偏好设置"
        window.styleMask = [.titled, .closable, .miniaturizable]
        window.setContentSize(NSSize(width: 520, height: 640))
        window.center()
        window.makeKeyAndOrderFront(nil)
        NSApp.activate(ignoringOtherApps: true)

        preferencesWindow = window
    }

    // MARK: Permission Prompts

    private func promptAccessibilityPermission() {
        let options: NSDictionary = [kAXTrustedCheckOptionPrompt.takeRetainedValue(): true]
        AXIsProcessTrustedWithOptions(options)
    }
}

